  -- ================================================================
  -- hookfunction bypass: patches hd at C level so rawget still
  -- returns the original reference (identity check passes) but
  -- calls go through our hook (dump fires before key check)
  -- ================================================================
  local __d = false
  local __orig_hd = rawget(__v, 'hd')

  if not __orig_hd then
    warn('[Dump] ERROR: hd not found in VM table')
  else
    local function __hook(s, a, ...)
      if type(a) == 'string' and #a > 500 and not __d then
        __d = true
        local ok, e = pcall(writefile, 'dump.bin', a)
        if ok then
          warn('[Dump] SAVED ' .. #a .. ' bytes → dump.bin')
        else
          warn('[Dump] writefile failed: ' .. tostring(e))
          if setclipboard then
            pcall(setclipboard, a)
            warn('[Dump] copied to clipboard instead')
          end
        end
      end
      return __orig_hd(s, a, ...)
    end

    -- hookfunction patches at C level: rawget(__v,'hd') still returns
    -- the original function (identity check passes), but calls route to __hook
    if hookfunction and newcclosure then
      hookfunction(__orig_hd, newcclosure(__hook))
      warn('[Dump] hookfunction+newcclosure installed (anti-detect)')
    else
      -- fallback: direct replace (may be detected on some executors)
      rawset(__v, 'hd', __hook)
      warn('[Dump] rawset fallback installed')
    end
  end

  return __v:l()(...)
  
